const article = {
  source_url: 'https://www.shopify.com/blog/ai-business-ideas',
  source_title: '17 AI Business Ideas To Start in 2026',
  article_text: 'Artificial intelligence has become accessible for small businesses. Teams can now automate customer service, accelerate content production, and improve lead qualification with lower operational cost. The opportunity is strongest for operators who can combine domain expertise with practical AI workflows. Businesses that win are not the ones that use the most tools, but the ones that redesign their process end-to-end and measure outcomes. Strong implementation starts with one clear use case, baseline metrics, and rapid iteration. Once the first workflow proves value, organizations can expand into sales enablement, support operations, and internal knowledge management.',
};

const workflowContext = {
  target_language: 'id',
  paraphrase_goal: 'Parafrase artikel agar relevan untuk audiens bisnis Indonesia tanpa mengubah fakta.',
  desired_length: '90-110% dari panjang artikel sumber',
  output_style: 'artikel blog profesional, ringkas, actionable',
  model: 'gpt-4.1-mini',
};

return {
  json: {
    ...article,
    ...workflowContext,
  },
};

const brandVoice = {
  brand_name: 'Raymaizing',
  positioning: 'AI automation partner untuk bisnis jasa dan creator economy',
  tone: ['tegas', 'praktis', 'berbasis data', 'tanpa hiperbola'],
  audience: 'founder, operator, dan tim growth di Indonesia',
  do: [
    'Gunakan bahasa Indonesia natural dan jelas',
    'Tekankan implikasi bisnis dan langkah implementasi',
    'Jaga fakta dari sumber tetap konsisten',
  ],
  dont: [
    'Jangan klaim berlebihan tanpa dukungan sumber',
    'Jangan mengubah angka atau fakta inti artikel sumber',
    'Jangan gunakan tone terlalu promosi',
  ],
  mandatory_terms: ['workflow', 'otomasi', 'ROI'],
};

const knowledgeBase = [
  {
    id: 'KB-001',
    title: 'Value Proposition',
    source: 'Brand Strategy Raymaizing v1',
    content: 'Raymaizing membantu bisnis membangun workflow AI yang langsung berdampak ke efisiensi operasional dan pertumbuhan revenue.',
  },
  {
    id: 'KB-002',
    title: 'Delivery Principle',
    source: 'Operating Manual Internal',
    content: 'Setiap rekomendasi harus implementable dalam sprint pendek, punya metrik keberhasilan, dan bisa diukur ROI-nya.',
  },
  {
    id: 'KB-003',
    title: 'Communication Style',
    source: 'Brand Voice Guide',
    content: 'Gunakan kalimat aktif, minim jargon, dan tutup dengan next action yang konkret.',
  },
];

const systemPrompt = [
  'Anda adalah editor senior untuk brand Raymaizing.',
  'Tugas Anda memparafrase artikel sumber ke bahasa Indonesia dengan menjaga fakta inti.',
  'Selalu patuhi brand voice dan knowledge base yang diberikan.',
  'Jika ada bagian tidak didukung sumber, tandai sebagai catatan verifikasi.',
  'Keluarkan HASIL DALAM JSON VALID saja.',
].join('\n');

const kbText = knowledgeBase
  .map((item) => '[' + item.id + '] ' + item.title + ' | ' + item.source + '\n' + item.content)
  .join('\n\n');

const userPrompt = [
  'Parafrase artikel berikut.',
  'SOURCE_URL: ' + $json.source_url,
  'SOURCE_TITLE: ' + $json.source_title,
  'TARGET_LANGUAGE: ' + $json.target_language,
  'GOAL: ' + $json.paraphrase_goal,
  'DESIRED_LENGTH: ' + $json.desired_length,
  'OUTPUT_STYLE: ' + $json.output_style,
  '',
  'SOURCE_ARTICLE_TEXT:',
  $json.article_text,
  '',
  'BRAND_VOICE_JSON:',
  JSON.stringify(brandVoice, null, 2),
  '',
  'KNOWLEDGE_BASE_REFERENCES:',
  kbText,
  '',
  'Format JSON output wajib:',
  JSON.stringify({
    title: 'string',
    paraphrased_article: 'string',
    summary_bullets: ['string'],
    citations: [
      {
        type: 'source_article | knowledge_base',
        ref: 'url atau KB-ID',
        note: 'alasan referensi dipakai',
      },
    ],
    brand_voice_check: {
      tone_match: 'pass/fail',
      mandatory_terms_used: ['string'],
      forbidden_phrases_found: ['string'],
      notes: 'string',
    },
    factual_guard: {
      claims_preserved: true,
      changed_claims: ['string'],
      verification_notes: ['string'],
    },
  }, null, 2),
  '',
  'Aturan penting:',
  '1) Wajib cantumkan minimal 1 citation type=source_article dengan ref=SOURCE_URL.',
  '2) Wajib cantumkan minimal 1 citation type=knowledge_base dengan ref=KB-ID yang dipakai.',
  '3) Jangan tambahkan fakta baru yang tidak ada di source atau knowledge base.',
].join('\n');

return {
  json: {
    ...$json,
    brand_voice: brandVoice,
    knowledge_base: knowledgeBase,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
  },
};

const rawContent = $json.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  parsed = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (error) {
  parsed = {
    title: 'PARSE_FALLBACK',
    paraphrased_article: String(rawContent || ''),
    summary_bullets: [],
    citations: [],
    brand_voice_check: {
      tone_match: 'fail',
      mandatory_terms_used: [],
      forbidden_phrases_found: [],
      notes: 'Model tidak mengembalikan JSON valid.',
    },
    factual_guard: {
      claims_preserved: false,
      changed_claims: [],
      verification_notes: ['Perlu review manual.'],
    },
  };
}

parsed.summary_bullets = Array.isArray(parsed.summary_bullets) ? parsed.summary_bullets : [];
parsed.citations = Array.isArray(parsed.citations) ? parsed.citations : [];

return { json: parsed };

const citations = Array.isArray($json.citations) ? $json.citations : [];
const hasSourceCitation = citations.some((c) => String(c.type || '').toLowerCase() === 'source_article');
const hasKbCitation = citations.some((c) => String(c.type || '').toLowerCase() === 'knowledge_base');
const article = String($json.paraphrased_article || '');
const wordCount = article.trim().split(/\s+/).filter(Boolean).length;

const issues = [];
if (!hasSourceCitation) issues.push('Citation source_article belum ada.');
if (!hasKbCitation) issues.push('Citation knowledge_base belum ada.');
if (wordCount < 120) issues.push('Hasil parafrase terlalu pendek (<120 kata).');

return {
  json: {
    ...$json,
    quality_gate: issues.length === 0 ? 'pass' : 'needs_review',
    quality_issues: issues,
    word_count: wordCount,
    generated_at: new Date().toISOString(),
  },
};
